import argparse
import json
import pickle
from pathlib import Path
from collections import defaultdict
import numpy as np
import heapq
import glob
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist", "alpha": 2.5, "beta": 1.3}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    if 'outdoor' in pstr: return 'outdoor'
    return 'room'

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0]

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        return neighbors[0]

    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = [n for n in neighs if n in node_dict]
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def get_edge_distance(a, b):
        return ((a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2) ** 0.5

    def shortest_path_distance(start, goal):
        if start == goal:
            return 0.0
        pq = [(0.0, start)]
        dists = {start: 0.0}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                return d
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    heapq.heappush(pq, (new_d, neigh))
        return float('inf')

    def find_next_on_path(start, goal):
        if start == goal:
            return start
        pq = [(0.0, start)]
        dists = {start: 0.0}
        prev = {start: None}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    prev[neigh] = curr
                    heapq.heappush(pq, (new_d, neigh))
        if goal not in prev:
            return None
        curr = goal
        while prev.get(curr) != start and prev.get(curr) is not None:
            curr = prev[curr]
        return curr

    alpha = model.get("alpha", 2.5)
    beta = model.get("beta", 1.0)
    best_score = -float('inf')
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = shortest_path_distance(current_pos, tcoord)
        if dist == float('inf') or dist <= 0.0:
            continue
        score = (util ** beta) / (dist ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        if best_n is not None:
            return best_n
        return neighbors[0] if neighbors else None

    next_coord = find_next_on_path(current_pos, best_target)
    if next_coord is None or next_coord == current_pos:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        if best_n is not None:
            return best_n
        return neighbors[0] if neighbors else None

    next_tuple = coord_to_tuple(next_coord)
    for neigh in neighbors:
        if coord_to_tuple(neigh) == next_tuple:
            return neigh
    return np.array([next_coord[0], next_coord[1]], dtype=np.float32)

def run_evaluation(model, data_path):
    data_path = Path(data_path)
    eval_config_path = data_path / "eval_config.json"
    map_paths = []
    if eval_config_path.exists():
        with open(eval_config_path, "r") as f:
            config = json.load(f)
        if "map_paths" in config and config["map_paths"]:
            map_paths = [data_path / p for p in config["map_paths"]]
            print(f"Using eval_config.json with {len(map_paths)} maps.")
    if not map_paths:
        print("No eval_config.json or empty, using 3 training maps per type for local testing.")
        for typ in ["room", "tunnel", "outdoor"]:
            pattern = str(data_path / "maps_train" / typ / "*.png")
            maps = glob.glob(pattern)[:3]
            map_paths.extend([Path(m) for m in maps])
    print(f"Evaluating on {len(map_paths)} maps.")
    results = []
    per_type = defaultdict(lambda: {"success": [], "explored": [], "distance": []})
    for map_path in map_paths:
        env_type = get_env_type(map_path)
        try:
            env = ExplorationEnv(map_path=str(map_path))
            obs = env.reset()
            step = 0
            max_steps = 128
            while step < max_steps:
                target = select_waypoint(obs, model)
                if target is None:
                    break
                obs, info = env.step(target)
                step += 1
                if obs.get("explored_rate", 0.0) >= 0.9999:
                    break
            metrics = env.get_metrics()
            success = 1 if metrics.get("success", False) or metrics.get("explored_rate", 0.0) > 0.9999 else 0
            explored_rate = metrics.get("explored_rate", 0.0)
            travel_distance = metrics.get("travel_distance", 0.0)
            results.append({
                "map_path": str(map_path.name),
                "env_type": env_type,
                "success": success,
                "travel_distance": float(travel_distance),
                "explored_rate": float(explored_rate)
            })
            per_type[env_type]["success"].append(success)
            per_type[env_type]["explored"].append(explored_rate)
            if success:
                per_type[env_type]["distance"].append(travel_distance)
        except Exception as e:
            print(f"Error processing {map_path}: {str(e)}")
            results.append({
                "map_path": str(map_path.name),
                "env_type": env_type,
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0
            })
            per_type[env_type]["success"].append(0)
            per_type[env_type]["explored"].append(0.0)
    total_episodes = len(results)
    success_rate = np.mean([r["success"] for r in results]) if results else 0.0
    explored_rate_mean = np.mean([r["explored_rate"] for r in results]) if results else 0.0
    successful_dists = [r["travel_distance"] for r in results if r.get("success", 0) == 1]
    travel_distance_mean = np.mean(successful_dists) if successful_dists else 0.0
    per_type_dict = {}
    for t in per_type:
        stats = per_type[t]
        n = len(stats["success"])
        sr = float(np.mean(stats["success"])) if n > 0 else 0.0
        er = float(np.mean(stats["explored"])) if n > 0 else 0.0
        ds = stats["distance"]
        dm = float(np.mean(ds)) if ds else 0.0
        per_type_dict[t] = {
            "explored_rate": er,
            "travel_distance": dm,
            "success_rate": sr
        }
    if successful_dists:
        s_terms = [300.0 / d for d in successful_dists]
        exploration_score = (success_rate * np.mean(s_terms))
    else:
        exploration_score = 0.0
    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate_mean:.4f}, Avg dist: {travel_distance_mean:.2f}")
    print(f"Proxy exploration_score: {exploration_score:.4f}")
    output = {
        "explored_rate": float(explored_rate_mean),
        "travel_distance": float(travel_distance_mean),
        "success_rate": float(success_rate),
        "per_episode": results,
        "per_type": per_type_dict,
        "total_episodes": int(total_episodes)
    }
    return output

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, default="/data")
    parser.add_argument("--checkpoint", type=str, default="checkpoints/baseline")
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    model = load_model(args.checkpoint)
    output_dict = run_evaluation(model, args.data_path)
    with open(args.output, "w") as f:
        json.dump(output_dict, f, indent=2)
    print("Local test on train subset done.")
